    // Settings State
    const [settingsForm, setSettingsForm] = useState({
        title: '',
        date: '',
        sport: '',
        purseValue: 0,
        basePrice: 0,
        bidIncrement: 0,
        playersPerTeam: 0,
        totalTeams: 0
    });
    const [slabs, setSlabs] = useState<BidIncrementSlab[]>([]);
    const [newSlab, setNewSlab] = useState<{from: string, increment: string}>({from: '', increment: ''});

