        }

        setRegConfig(prev => ({
            ...prev,
            customFields: [...prev.customFields, { ...newField, id: fieldId, options: processedOptions }]
        }));

        // Reset builder
        setNewField({ id: '', label: '', type: 'text', required: false });
        setDropdownOptionsInput('');
    };

    const removeCustomField = (idx: number) => {
        setRegConfig(prev => ({
