                        className={`bg-green-600 hover:bg-green-700 text-white font-bold py-3 px-6 rounded shadow-lg w-full md:w-auto transition-all ${loading ? 'opacity-70 cursor-not-allowed' : ''}`}
                    >
                        {loading ? 'Saving...' : 'Create Auction'}
                    </button>
                </div>

            </form>
        </div>
      </main>
    </div>
  );
};

